import{_ as i,o as a,c as e,ae as t}from"./chunks/framework.RRduUuAx.js";const c=JSON.parse('{"title":"书籍推荐及我的2021年阅读计划","description":"","frontmatter":{},"headers":[],"relativePath":"books/read/书单.md","filePath":"books/read/书单.md","lastUpdated":1609514927000}'),r={name:"books/read/书单.md"};function o(p,l,s,d,n,_){return a(),e("div",null,[...l[0]||(l[0]=[t('<h1 id="书籍推荐及我的2021年阅读计划" tabindex="-1">书籍推荐及我的2021年阅读计划 <a class="header-anchor" href="#书籍推荐及我的2021年阅读计划" aria-label="Permalink to &quot;书籍推荐及我的2021年阅读计划&quot;">​</a></h1><h2 id="看过的书" tabindex="-1">看过的书 <a class="header-anchor" href="#看过的书" aria-label="Permalink to &quot;看过的书&quot;">​</a></h2><p>列举一下近几年看过觉得比较好的文学类的书：</p><p>这里说的好，有故事性、启发性等。</p><p>我想，一千个读者就有一千个哈姆雷特。</p><p>不要期望一定从阅读中得到什么，影响是潜移默化的，就像的复旦的“自由而无用”。</p><p>（1）东野圭吾</p><ul><li>《白夜行》</li><li>《解忧杂货铺》</li><li>《嫌疑人X的献身》</li></ul><p>（2）治愈系</p><ul><li>《岛上书店》</li><li>《追风筝的人》</li><li>《群山回响》</li><li>《灿烂千阳》</li><li>《偷影子的人》</li></ul><p>（3）实用、社科类</p><ul><li>《原则》</li><li>《乌合之众》</li><li>《非暴力沟通》</li><li>《富爸爸穷爸爸》</li><li>《高效能人士的七个习惯》</li><li>《断舍离》</li></ul><p>（4）纯文学</p><ul><li>《简爱》</li><li>《黄金时代》</li><li>《人间失格》</li><li>《月亮与六便士》</li><li>《小王子》</li></ul><h2 id="我的2021年阅读计划" tabindex="-1">我的2021年阅读计划 <a class="header-anchor" href="#我的2021年阅读计划" aria-label="Permalink to &quot;我的2021年阅读计划&quot;">​</a></h2><p>工作比较忙，立个flag，十二个月，争取每个月完成一本。</p><ul><li>一月。《穷查理宝典》</li><li>二月。《论法的精神（上）》</li><li>三月。《论法的精神（下）》</li><li>四月。《三体》</li><li>五月。《北京折叠》</li><li>六月。《人生海海》</li><li>七月。《流浪的地球》</li><li>八月。《遥远的救世主》</li><li>九月。《心》</li><li>十月。《干法》</li><li>十一月。《活法》</li><li>十二月。《人类简史》</li></ul>',17)])])}const h=i(r,[["render",o]]);export{c as __pageData,h as default};
